<? function chopline($str) { return preg_replace("/\r?\n$|\r[^\n]$/", "", $str); }function addjsslashes($str) { return addcslashes($str, "\0..\37!@\@\177..\377\'\""); }if($_POST) { extract($_POST, EXTR_PREFIX_SAME, "post_"); }if($_GET) { extract($_GET, EXTR_PREFIX_SAME, "get_"); }$file = "notes.txt.php";$n = 0;$list = array();$fp = fopen($file, "r");while (!feof($fp)) {	$time = fgets($fp, 1024);	$text = fgets($fp, 9999);	if ($time && $text) {		$list[$n][0]= chopline($time);		$list[$n][1]= stripcslashes(chopline($text));		$n++; } }fclose($fp);if($act == "del") {	array_splice($list, $nr, 1); }	if($act == "add") {	$s = sizeof($list);	$list[$s][0] = time();	$list[$s][1] = stripcslashes($newtext); }	if($act == "edit") {	$list[$nr][0] = time();	$list[$nr][1] = stripcslashes($newtext);  }array_multisort($list);if($act) {	$fp = fopen($file, "w");	for ($i=0; $i<sizeof($list); $i++) {  		fputs($fp, $list[$i][0]."\n");  		fputs($fp, addjsslashes($list[$i][1])."\n"); }	fclose($fp);	header("Location: notities.php"); }include("header.php"); ?><script language="javascript">    function switchform(n)    {        switch (n) {        <? for ($i = 0; $i < sizeof($list); $i++) { ?>            case <? echo $i ?>:                document.frm.nr.value = '<? echo $i ?>';                document.frm.newtext.value = '<? echo addjsslashes($list[$i][1]) ?>';				document.frm.newtext.focus();                break;        <? } ?>        }    }	    function add()    {        document.frm.action = "notities.php?act=add";		document.frm.submit();    }        function edit()    {        document.frm.action = "notities.php?act=edit";        if(document.frm.nr.value == "-1") {			alert('Nothing to change ! \n Wanna add ?'); 		} else {        	document.frm.submit();		}    }</script><p>&nbsp;</p><table width="560" cellspacing="0" cellpadding="4" border="0"><tr class="row"><td width="15%"></td><td class="row" width="65%">Notities</td><td class="row"width="20%">Acties</td></tr><?for ($i=sizeof($list)-1; $i>=0; $i--) {	if (round($i/2) != $i/2) { echo "<tr class=light>"; } else { echo "<tr>"; }	echo "<td valign=top>".date("d/m/Y", $list[$i][0])."</td>";	echo "<td>".nl2br($list[$i][1])."</td>";	echo "<td valign=top><a href=javascript:switchform($i)>bewerk</a> | ";	echo "<a href=\"notities.php?act=del&nr=".$i."\">weg</a></td></tr>"; }?><form name="frm" method="post"><input type="hidden" name="nr" value="-1"><tr><td colspan="3">&nbsp;</td></tr><tr class="row"><td></td><td class="row" colspan="3">notitie toevoegen of bewerken</td></tr><tr><td valign=top>note:</td><td ><textarea rows="5" name="newtext" style="width:340px"></textarea></td><td valign=top><a href="javascript:add()">voeg toe</a> | <a href="javascript:edit()">sla op</a></td></tr></form></table><? include("footer.php"); ?>